<script>
  import { values, td_values, format } from "../stores/simulation";
  import { getDictionary } from "../stores/locale";

  const dict = getDictionary()

  $: elwi = format($td_values.elwi, 0, "**");
  $: pvpi = format($td_values.pvpi, 1, "*.*");
  $: td_cipc = format($td_values.td_cipc, 2, "*.**");
  $: gedi = format($td_values.gedi, 0, "**");
  $: gef = format($td_values.gef, 0, "***");
  $: cfi = format($td_values.cfi,1, "*.*");

   $: cipc = format($td_values.dirty || $values.sendCO ? $values.derived.cipc : null, 2, "*.**");
  $: svv = format($td_values.dirty || $values.sendCO ? $values.derived.svv : null, 0, "**");
  $: tb = format($values.derived.tb, 1, "*.*");
  $: svri = format($values.derived.svri, 0, "****");

  const range = (x, verylow, low, high, veryhigh, dependentOnTd = true) => {
    if (!$td_values.dirty && dependentOnTd == true) return "inactive";
    if (verylow && x < verylow) return "verylow";
    if (low && x < low) return "low";
    if (veryhigh && x > veryhigh) return "veryhigh";
    if (high && x > high) return "high";
    return "ok";
  };

  const t = 0.2;

  $: elwi_range = range($td_values.elwi, 3, null, 7, 15);
  $: pvpi_range = range($td_values.pvpi, 1, null, null, 3);
  $: gedi_range = range(
    $td_values.gedi,
    680 * (1 - t),
    680,
    800,
    800 * (1 + t)
  );


  $: svv_range = $values.sendCO ? range($values.derived.svv, null, null, 10, 10 * (1 + t),false) : range($values.derived.svv, null, null, 10, 10 * (1 + t));
  $: cipc_range = $values.sendCO ? range($values.derived.cipc, 3 * (1 - t), 3, 5, 5 * (1 + t), false): range($values.derived.cipc, 3 * (1 - t), 3, 5, 5 * (1 + t));


  $: gef_range = range($td_values.gef, 25 * (1 - t), 25, 35, 35 * (1 + t));
  $: cfi_range = range($td_values.cfi, 4.5 * (1 - t), 4.5, 4.6, 4.6 * (1 + t));
  $: svri_range = range(
    $values.derived.svri,
    1700 * (1 - t),
    1700,
    2400,
    2400 * (1 + t),
    false
  );

  $: gef_nromalized =
    gef !== Infinity &&
    gef !== -Infinity &&
    gef !== "Infinity" &&
    gef !== "-Infinity"
      ? gef
      : "***";
  $: cfi_normalized =
    cfi !== Infinity &&
    cfi !== -Infinity &&
    cfi !== "Infinity" &&
    cfi !== "-Infinity"
      ? cfi
      : "*.*";

  const handleOpenTD = () => {
    if ($values.td_available) {
      $values.td_open = true;
    } else {
      alert("App has not received a simulation signal yet.");
    }
  };
</script>

